class Solution:
    def originalDigits(self, s: str) -> str:

        freq = Counter(s)
        counts = {i: 0 for i in range(10)}

        processing_order = [
            (0, 'z', {'z':1, 'e':1, 'r':1, 'o':1}),
            (2, 'w', {'w':1, 't':1, 'o':1}),
            (4, 'u', {'u':1, 'f':1, 'o':1, 'r':1}),
            (6, 'x', {'x':1, 's':1, 'i':1}),
            (8, 'g', {'g':1, 'e':1, 'i':1, 'h':1, 't':1}),
            (1, 'o', {'o':1, 'n':1, 'e':1}),
            (3, 'h', {'t':1, 'h':1, 'r':1, 'e':2}),
            (5, 'f', {'f':1, 'i':1, 'v':1, 'e':1}),
            (7, 's', {'s':1, 'e':1, 'v':1, 'n':1}),
            (9, 'i', {'i':1, 'n':2, 'e':1}),
        ]

        for digit, unique_char, letters in processing_order:
            count = freq.get(unique_char, 0)
            counts[digit] = count
            for char, cnt in letters.items():
                if char in freq:
                    freq[char] -= cnt * count
                    if freq[char] < 0:
                        freq[char] = 0

        result = []
        for i in range(10):
            result.append(str(i) * counts[i])
        return ''.join(result)

